example.code:
var attributeValues = new Dictionary<string, string>() {
    { "StartMeasurement", "True" },
    { "PreMeasurementDelay", "1" },
    { "SamplingRatio", "1" },
    { "SamplingMode", "Average" },
    { "SamplingCount", "1" }
};
var pin = Prime.Services.PinService.Get("MyHcDps");
pin.SetPinAttributeValues(attributeValues);
